param(
    [string]$BaseUrl = "http://localhost:9090",
    [string]$UserToken = "Bearer c025e987-3b46-4cd9-805e-f5649166b8e5",
    [string]$AdminToken = "Bearer 7dd54bdd-ce10-4ec7-b258-b278df5733c7",
    [string]$ReportDir = "",
    [int]$SkuId = 1,
    [int]$RequestTimeoutSec = 12,
    [int]$BatchTimeoutSec = 180,
    [switch]$ContinueOnFailure
)
$ErrorActionPreference = "Stop"
$script:Results = New-Object System.Collections.Generic.List[object]
$script:Context = @{}
$script:StartTime = Get-Date
$script:BatchDeadline = (Get-Date).AddSeconds($BatchTimeoutSec)
if ([string]::IsNullOrWhiteSpace($ReportDir)) { $ReportDir = Join-Path $PSScriptRoot "..\test-reports" }
if (-not (Test-Path $ReportDir)) { New-Item -ItemType Directory -Force -Path $ReportDir | Out-Null }
$script:Stamp = Get-Date -Format "yyyyMMdd-HHmmss"
$script:InitialReportPath = Join-Path $ReportDir ("p2-business-flow-initial-{0}.md" -f $script:Stamp)
$script:DetailReportPath = Join-Path $ReportDir ("p2-business-flow-detail-{0}.md" -f $script:Stamp)
function Add-TestResult([string]$Suite,[string]$Name,[string]$Status,[string]$Detail="",[int]$ElapsedMs=0){$script:Results.Add([pscustomobject]@{suite=$Suite;name=$Name;status=$Status;detail=$Detail;elapsedMs=$ElapsedMs;time=(Get-Date).ToString("yyyy-MM-dd HH:mm:ss")})|Out-Null}
function Test-BatchDeadline{if((Get-Date)-gt $script:BatchDeadline){throw "Batch timeout exceeded after $BatchTimeoutSec seconds"}}
function Mask-Token([string]$Token){if($Token.Length -lt 24){return "***"};return ($Token.Substring(0,15)+"****"+$Token.Substring($Token.Length-8))}
function Get-ResponseData($Response){if($null -eq $Response){return $null};if($Response.PSObject.Properties.Name -contains "data"){return $Response.data};return $Response}
function Get-CaseStatus([string]$Message){if($Message -match 'TIMEOUT|timeout|timed out'){return 'TIMEOUT'};if($Message -match '401|403|Unauthorized|Forbidden|permission'){return 'BLOCKED'};if($Message -match 'missing|precondition|not found'){return 'SKIP'};return 'FAIL'}
function Invoke-MallApi{param([string]$Method,[string]$Path,[object]$Body=$null,[string]$Token="",[switch]$AllowFailure,[int]$TimeoutSec=$RequestTimeoutSec)
    Test-BatchDeadline;$headers=@{};if(-not [string]::IsNullOrWhiteSpace($Token)){$headers["Authorization"]=$Token}
    $params=@{Method=$Method;Uri="$BaseUrl$Path";Headers=$headers;ContentType="application/json; charset=utf-8";TimeoutSec=$TimeoutSec};if($null -ne $Body){$params.Body=($Body|ConvertTo-Json -Depth 30)}
    try{$response=Invoke-RestMethod @params}catch{$message="HTTP request failed: $Method $Path | $($_.Exception.Message)";if($_.Exception.Message -match 'timeout|timed out'){$message="TIMEOUT: $Method $Path exceeded ${TimeoutSec}s"};if($AllowFailure){return [pscustomobject]@{success=$false;message=$message;data=$null}};if($message -like 'TIMEOUT:*'){throw [System.TimeoutException]::new($message)};throw $message}
    if($response.PSObject.Properties.Name -contains "success" -and $response.success -eq $false){if($AllowFailure){return $response};$msg=if($response.message){$response.message}else{$response.msg};throw "Business response failed: $Method $Path | $msg"}
    return $response
}
function Invoke-Case([string]$Suite,[string]$Name,[scriptblock]$Script){Test-BatchDeadline;$sw=[System.Diagnostics.Stopwatch]::StartNew();try{$detail=& $Script;$sw.Stop();Add-TestResult $Suite $Name "PASS" ([string]$detail) $sw.ElapsedMilliseconds;Write-Host "[PASS] $Suite - $Name" -ForegroundColor Green}catch [System.TimeoutException]{$sw.Stop();Add-TestResult $Suite $Name "TIMEOUT" $_.Exception.Message $sw.ElapsedMilliseconds;Write-Host "[TIMEOUT] $Suite - $Name : $($_.Exception.Message)" -ForegroundColor Yellow;if(-not $ContinueOnFailure){throw}}catch{$sw.Stop();$status=Get-CaseStatus $_.Exception.Message;Add-TestResult $Suite $Name $status $_.Exception.Message $sw.ElapsedMilliseconds;Write-Host "[$status] $Suite - $Name : $($_.Exception.Message)" -ForegroundColor Red;if(-not $ContinueOnFailure -and $status -eq "FAIL"){throw}}}
function Write-InitialReport{$lines=@("# mallFei P2 Smoke Test Initial Report","","- BaseUrl: $BaseUrl","- StartedAt: $($script:StartTime.ToString('yyyy-MM-dd HH:mm:ss'))","- RequestTimeoutSec: $RequestTimeoutSec","- BatchTimeoutSec: $BatchTimeoutSec","","## Planned cases","- [P2Setup] create paid order as target","- [P2AdminWrite] dashboard/profile/config","- [P2StockWrite] stock policy/warning/adjust","- [P2OnlineReconcile] create/generate/match/archive","- [P2PayException] pay sync/repair/exception","- [P2Negative] auth and parameter interception");$lines|Set-Content -Path $script:InitialReportPath -Encoding UTF8;Write-Host "Initial report written: $script:InitialReportPath" -ForegroundColor Cyan}
function Write-FormalReport{$pass=($script:Results|Where-Object status -eq "PASS").Count;$fail=($script:Results|Where-Object status -eq "FAIL").Count;$timeout=($script:Results|Where-Object status -eq "TIMEOUT").Count;$skip=($script:Results|Where-Object status -eq "SKIP").Count;$blocked=($script:Results|Where-Object status -eq "BLOCKED").Count;$warn=($script:Results|Where-Object status -eq "WARN").Count;$duration=[int]((Get-Date)-$script:StartTime).TotalSeconds;$conclusion=if(($fail+$timeout+$blocked)-eq 0){"P2 smoke tests passed"}else{"P2 smoke tests have failed or blocked cases"};$lines=New-Object System.Collections.Generic.List[string];foreach($l in @("# mallFei P2 API Smoke Test Report","","## 1. Test Conclusion","","P2 automated API smoke tests have been executed against '$BaseUrl.","","- Test time: $($script:StartTime.ToString('yyyy-MM-dd HH:mm:ss'))","- Script: backend/scripts/p2-business-flow-tests.ps1","- Initial report: backend/test-reports/$(Split-Path $script:InitialReportPath -Leaf)","- Detail report: backend/test-reports/$(Split-Path $script:DetailReportPath -Leaf)","- Duration: ${duration}s","- Result: PASS=${pass}, FAIL=${fail}, TIMEOUT=${timeout}, SKIP=${skip}, BLOCKED=${blocked}, WARN=${warn}","- Overall conclusion: $conclusion","","## 2. Request Parameter Construction","","### 2.1 Basic Config","","| Config | Value |","| --- | --- |","| BaseUrl | $BaseUrl |","| User Token | $(Mask-Token $UserToken) |","| Admin Token | $(Mask-Token $AdminToken) |","| Test SKU | $SkuId |","| Request timeout | ${RequestTimeoutSec}s |","| Batch timeout | ${BatchTimeoutSec}s |","","### 2.2 Key Parameters","","- Stock policy update uses stockStatus=NORMAL, lowStockThreshold=1, highStockThreshold=9999.","- Stock manual adjustment uses adjustmentType=REPLENISH, changeQuantity=1.","- Online reconciliation task uses channel=MOCK, reconcileDate=$($script:Context.reconcileDate).","- Payment exception endpoints reuse test order $($script:Context.orderNo).","","## 3. Execution Result Details","","| Suite | Case | Status | Elapsed ms | Key Result |","| --- | --- | --- | ---: | --- |")){$lines.Add($l)|Out-Null};foreach($r in $script:Results){$lines.Add("| $($r.suite) | $($r.name) | $($r.status) | $($r.elapsedMs) | $(($r.detail -replace '\|','\\|')) |")|Out-Null};foreach($l in @("","## 4. Issues and Handling","",$(if(($fail+$timeout+$blocked+$skip)-eq 0){"No FAIL, TIMEOUT, SKIP or BLOCKED cases were found in this P2 run."}else{"There are non-pass cases. Check FAIL, TIMEOUT, BLOCKED and SKIP rows first."}),"","## 5. Current Coverage","","- Admin dashboard, current admin and profile update endpoints.","- Product sales threshold config query and update.","- Admin stock policy adjustment, warning handling and manual adjustment.","- Online reconciliation task create, bill generation, matching, diff query and archive.","- Admin payment sync, payment repair and payment exception handling endpoints.","- No-token, user-token-to-admin and invalid parameter negative checks.","","## 6. Not Covered / Next Extensions","","- Full aftersale refund closed loop.","- File upload with local storage and MinIO.","- Full admin product create/update/status change with data rollback.","- Online reconciliation diff handling, hanging follow-up and finance transfer when diffs exist.","- Concurrent duplicate pay/refund/ship/stock reservation scenarios.","- More complete permission matrix validation.","","## 7. ApiPost Suggestions","","- Configure baseUrl, userToken, adminToken and skuId.","- Create a paid order first, then reuse orderNo and payOrderNo.","- Run stock write operations, online reconciliation and payment exception endpoints in separate folders.","- Put negative tests in a separate folder and assert rejection.","- Use test account and test SKU for write operations.","","## 8. Conclusion","","This P2 run focuses on deeper admin writes, online reconciliation, payment exception handling and negative interception. Overall conclusion: $conclusion.")){$lines.Add($l)|Out-Null};$lines|Set-Content -Path $script:DetailReportPath -Encoding UTF8;Write-Host "Final report written: $script:DetailReportPath" -ForegroundColor Cyan}
function New-TestOrder{$order=Invoke-MallApi -Method POST -Path "/api/orders" -Token $UserToken -Body @{receiverName="P2 Auto User";receiverPhone="13800000000";receiverProvinceName="Beijing";receiverCityName="Beijing";receiverDistrictName="Chaoyang";receiverDetailAddress="P2 Auto Address";remark="p2 business flow test";items=@(@{skuId=$SkuId;quantity=1})};$data=Get-ResponseData $order;$script:Context.orderNo=$data.orderNo;$script:Context.orderId=$data.id;$pay=Invoke-MallApi -Method POST -Path "/api/pay/orders?orderNo=$($data.orderNo)&payChannel=MOCK&returnPath=/orders" -Token $UserToken;$payData=Get-ResponseData $pay;$script:Context.payOrderNo=$payData.payOrderNo;Invoke-MallApi -Method POST -Path "/api/pay/callback/mock-success?orderNo=$($data.orderNo)" -Token $UserToken|Out-Null;return "orderNo=$($data.orderNo) payOrderNo=$($payData.payOrderNo)"}
Write-InitialReport
try{
Invoke-Case "P2Setup" "create paid order as payment exception and admin operation target" { New-TestOrder }
Invoke-Case "P2AdminWrite" "dashboard me and profile update are reachable" { Invoke-MallApi -Method GET -Path "/api/admin/me" -Token $AdminToken|Out-Null;Invoke-MallApi -Method GET -Path "/api/admin/dashboard" -Token $AdminToken|Out-Null;Invoke-MallApi -Method PUT -Path "/api/admin/me/profile" -Token $AdminToken -Body @{nickname="P2 Admin Smoke";avatar=""} -AllowFailure|Out-Null;"admin me/dashboard/profile checked" }
Invoke-Case "P2AdminWrite" "product sales threshold config update" { Invoke-MallApi -Method GET -Path "/api/admin/products/sales-threshold-config" -Token $AdminToken|Out-Null;Invoke-MallApi -Method PUT -Path "/api/admin/products/sales-threshold-config" -Token $AdminToken -Body @{hotSalesThreshold=100;lowSalesThreshold=1}|Out-Null;"hotSalesThreshold=100 lowSalesThreshold=1" }
Invoke-Case "P2StockWrite" "stock policy warning adjust and consistency check" { Invoke-MallApi -Method PUT -Path "/api/admin/stocks/$SkuId/policy" -Token $AdminToken -Body @{stockStatus="NORMAL";lowStockThreshold=1;highStockThreshold=9999;reason="P2 smoke policy check"} -AllowFailure|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/stocks/$SkuId/warning-handle" -Token $AdminToken -Body @{action="IGNORE";note="P2 smoke warning handle"} -AllowFailure|Out-Null;$stockReason=([string]([char]0x91C7)+[string]([char]0x8D2D)+[string]([char]0x5165)+[string]([char]0x5E93));Invoke-MallApi -Method PUT -Path "/api/admin/stocks/$SkuId/adjust" -Token $AdminToken -Body @{adjustmentType="REPLENISH";changeQuantity=1;reason=$stockReason;remark="auto smoke"}|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/stocks/$SkuId/consistency-check" -Token $AdminToken|Out-Null;"skuId=$SkuId stock write endpoints checked" }
Invoke-Case "P2OnlineReconcile" "create task generate bills match query archive" { $date=(Get-Date).ToString("yyyy-MM-dd");$script:Context.reconcileDate=$date;$created=Invoke-MallApi -Method POST -Path "/api/admin/online-reconcile-tasks" -Token $AdminToken -Body @{reconcileDate=$date;channel="MOCK";remark="P2 smoke task"} -AllowFailure;$task=Get-ResponseData $created;$taskId=$task.id;if(-not $taskId){$tasks=Invoke-MallApi -Method GET -Path "/api/admin/online-reconcile-tasks?channel=MOCK&page=1&size=10" -Token $AdminToken;$taskData=Get-ResponseData $tasks;$records=$taskData.records;if(-not $records){$records=$taskData.list};if(-not $records){$records=$taskData.items};$existing=$records|Where-Object{$_.reconcileDate -eq $date -or $_.billDate -eq $date}|Select-Object -First 1;if(-not $existing){$existing=$records|Select-Object -First 1};if($existing){$taskId=$existing.id}else{throw "created or reusable reconcile task id missing"}};$script:Context.taskId=$taskId;Invoke-MallApi -Method GET -Path "/api/admin/online-reconcile-tasks/$taskId" -Token $AdminToken|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/online-reconcile-tasks/$taskId/local-bills/generate" -Token $AdminToken -AllowFailure|Out-Null;Invoke-MallApi -Method GET -Path "/api/admin/online-reconcile-tasks/$taskId/local-bills?page=1&size=10" -Token $AdminToken|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/online-reconcile-tasks/$taskId/channel-bills/mock-generate" -Token $AdminToken -Body @{mode="NORMAL"} -AllowFailure|Out-Null;Invoke-MallApi -Method GET -Path "/api/admin/online-reconcile-tasks/$taskId/channel-bills?page=1&size=10" -Token $AdminToken|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/online-reconcile-tasks/$taskId/match" -Token $AdminToken -AllowFailure|Out-Null;Invoke-MallApi -Method GET -Path "/api/admin/online-reconcile-tasks/$taskId/diff-items?page=1&size=10" -Token $AdminToken|Out-Null;Invoke-MallApi -Method GET -Path "/api/admin/online-reconcile-tasks/$taskId/logs?page=1&size=20" -Token $AdminToken|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/online-reconcile-tasks/$taskId/complete" -Token $AdminToken -Body @{remark="P2 smoke complete"} -AllowFailure|Out-Null;"taskId=$taskId reconcileDate=$date" }
Invoke-Case "P2PayException" "pay sync repair and payment exception endpoints" { $orderNo=$script:Context.orderNo;if(-not $orderNo){throw "orderNo missing"};Invoke-MallApi -Method POST -Path "/api/admin/pays/$orderNo/sync-status" -Token $AdminToken -AllowFailure|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/pays/$orderNo/repair-paid" -Token $AdminToken -AllowFailure|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/orders/$orderNo/payment-exception" -Token $AdminToken -Body @{note="P2 smoke mark"} -AllowFailure|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/orders/$orderNo/payment-exception/verify" -Token $AdminToken -AllowFailure|Out-Null;Invoke-MallApi -Method POST -Path "/api/admin/orders/$orderNo/payment-exception/pending-action" -Token $AdminToken -Body @{action="MANUAL_RECHECK";note="P2 smoke pending"} -AllowFailure|Out-Null;"orderNo=$orderNo payment exception endpoints attempted" }
Invoke-Case "P2Negative" "invalid no-token user-token-admin and bad-parameter interception" { $a=Invoke-MallApi -Method GET -Path "/api/admin/dashboard" -AllowFailure;$b=Invoke-MallApi -Method GET -Path "/api/admin/dashboard" -Token $UserToken -AllowFailure;$c=Invoke-MallApi -Method POST -Path "/api/cart/items" -Token $UserToken -Body @{skuId=$SkuId;quantity=-1} -AllowFailure;if($a.success -ne $false){throw "no-token admin dashboard was not rejected"};if($b.success -ne $false){throw "user-token admin dashboard was not rejected"};if($c.success -ne $false){throw "invalid cart quantity was not rejected"};"negative interception checked" }
Write-FormalReport
}catch{Write-FormalReport;throw}
if(($script:Results|Where-Object{$_.status -eq 'FAIL' -or $_.status -eq 'TIMEOUT' -or $_.status -eq 'BLOCKED'}).Count -gt 0){throw 'There are failed or blocked cases. Please check the reports.'}
Write-Host "All P2 automated test cases completed" -ForegroundColor Green


